#include <vector>
#include <cmath>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
		    std::vector<std::vector<double>>& L,
		    std::vector<double>& x,
		    std::vector<double>& b) {

    /* Forward substitution for a strictly lower–triangular matrix.
       Parallelisation is not possible because each iteration depends
       on the previous results, but inner loops can be vectorised. */
    for (int i = 0; i < n; ++i) {
        const double *row = L[i].data();     // pointer to current row of L
        double sum   = b[i];
        const double *x_ptr = x.data();
        // vectorised inner loop (SIMD hint)
        #pragma omp simd
        for (int j = 0; j < i; ++j) {
            sum -= row[j] * x_ptr[j];
        }
        // use reciprocal once to avoid division instruction
        x[i] = sum * (1.0 / row[i]);
    }
}
