/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {

  constexpr double inv3 = 1.0 / 3.0;          // avoid using a non‑constant literal
  double *restrict a = A.data();              // use raw pointers for speed
  double *restrict b = B.data();

  /* The two inner loops are independent; they can be parallelised.
     OpenMP will automatically distribute iterations among the 8 threads. */
  for (int t = 0; t < tsteps; ++t) {

    #pragma omp parallel for schedule(static)
    for (int i = 1; i < n - 1; ++i) {
      /* 3‑point averaging */
      b[i] = inv3 * (a[i-1] + a[i] + a[i+1]);
    }

    #pragma omp parallel for schedule(static)
    for (int i = 1; i < n - 1; ++i) {
      a[i] = inv3 * (b[i-1] + b[i] + b[i+1]);
    }
  }
}
