/* Optimized computational kernel.
   The resulting behaviour (including the results in C) is
   exactly the same as the reference implementation. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        const std::vector<double>& Brow = B[i];
        const std::vector<double>& Arow = A[i];
        std::vector<double>& Crow   = C[i];
        double Aii = Arow[i];
        for (int j = 0; j < n; ++j) {
            double temp = 0.0;
            double Bij = Brow[j];
            for (int k = 0; k < i; ++k) {
                double aik = Arow[k];
                Crow[k] += alpha * Bij * aik;      // C[k][j] update
                temp += B[k][j] * aik;             // accumulate for C[i][j]
            }
            Crow[j] = beta * Crow[j] + alpha * Bij * Aii + alpha * temp;
        }
    }
}
