void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Flatten the 2‑D vector for cache friendliness
    // Each row is contiguous, so we can obtain a pointer to the start of a row.
    std::vector<int*> rows(n);
    for (int i = 0; i < n; ++i) rows[i] = path[i].data();

    // Parallelize over k and i.   
    // Two levels of parallelism give enough work for 8 threads.
    #pragma omp parallel for schedule(static, 64) collapse(2)
    for (int k = 0; k < n; ++k) {
        int* pk = rows[k];
        for (int i = 0; i < n; ++i) {
            int* pi = rows[i];
            int via = pi[k];          // path[i][k]
            for (int j = 0; j < n; ++j) {
                int newDist = via + pk[j];
                int cur = pi[j];
                if (newDist < cur) pi[j] = newDist;
            }
        }
    }
}
