/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // pointers to the row data for quick access
    std::vector<double*> Ac(m);
    std::vector<double*> Cc(n);
    for (int i = 0; i < m; ++i) Ac[i] = A[i].data();
    for (int i = 0; i < n; ++i) Cc[i] = C[i].data();

    /* Parallelise the outer loop over the rows of C. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* ci   = Cc[i];
        double* ai   = Ac[i];
        /* beta‑scaling of the lower triangular part of row i */
        for (int j = 0; j <= i; ++j) ci[j] *= beta;

        /* Horner‑style accumulation of the dot products */
        for (int k = 0; k < m; ++k) {
            double aik = ai[k];
            if (aik==0.0) continue;          // skip zero patterns
            double* ak = Ac[k];
            for (int j = 0; j <= i; ++j) {
                ci[j] += alpha * aik * ak[j];
            }
        }
    }
}
