#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Work space allocated once to avoid temporaries in the innermost loop.
    std::vector<double> z(n);

    double beta  = 1.0;
    double alpha = -r[0];
    y[0] = -r[0];

    // Browse the rows of the matrix over which the recursion is performed.
    for (int k = 1; k < n; ++k) {
        // Update beta and perform the dot product: sum = r[k‑1‑i] * y[i]
        beta = (1.0 - alpha * alpha) * beta;
        double sum = 0.0;
#pragma omp simd reduction(+:sum)
        for (int i = 0; i < k; ++i)
            sum += r[k - i - 1] * y[i];

        alpha = -(r[k] + sum) / beta;

        // Update the forward coefficients (y[0 … k‑1]) using z as temporary.
#pragma omp simd
        for (int i = 0; i < k; ++i)
            z[i] = y[i] + alpha * y[k - i - 1];

        // Move the updated values back to y.
#pragma omp simd
        for (int i = 0; i < k; ++i)
            y[i] = z[i];

        // Store the newest coefficient.
        y[k] = alpha;
    }
}
