void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    // The 2‑D array is stored as a vector of vectors.  For speed it is
    // accessed with raw pointers after the row is obtained.
    for (int t = 0; t < tsteps; ++t) {
        // Update every interior cell.  OpenMP is used only on the
        // spatial loops – the time step loop is intentionally left
        // serial to preserve the exact data dependence.
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            // Obtain the pointer to the current row for fast indexing.
            double* row    = A[i].data();
            double* rowm1 = A[i - 1].data();
            double* rowp1 = A[i + 1].data();
            for (int j = 1; j <= n - 2; ++j) {
                // Compute the average of the 3×3 stencil.
                row[j] = (rowm1[j - 1] + rowm1[j] + rowm1[j + 1] +
                          row[j - 1] + row[j] + row[j + 1] +
                          rowp1[j - 1] + rowp1[j] + rowp1[j + 1]) / 9.0;
            }
        }
    }
}
