void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    // Parallel over rows
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp_val = 0.0;
        double y_val   = 0.0;

        const double* restrict a_row = A[i].data();
        const double* restrict b_row = B[i].data();
        const double* restrict x_ptr = x.data();

        // Unroll 4-fold for better throughput
        int j = 0;
        for (; j <= n - 4; j += 4) {
            tmp_val += a_row[j]   * x_ptr[j];
            y_val   += b_row[j]   * x_ptr[j];
            tmp_val += a_row[j+1] * x_ptr[j+1];
            y_val   += b_row[j+1] * x_ptr[j+1];
            tmp_val += a_row[j+2] * x_ptr[j+2];
            y_val   += b_row[j+2] * x_ptr[j+2];
            tmp_val += a_row[j+3] * x_ptr[j+3];
            y_val   += b_row[j+3] * x_ptr[j+3];
        }
        for (; j < n; ++j) {
            tmp_val += a_row[j] * x_ptr[j];
            y_val   += b_row[j] * x_ptr[j];
        }

        tmp[i] = tmp_val;
        y[i]   = alpha * tmp_val + beta * y_val;
    }
