/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
		double alpha,
		double beta,
		std::vector<std::vector<double>>& tmp,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D) {

    /* First matrix product:  tmp = alpha * A * B  (ni x nj matrix) */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* restrict tmp_row = tmp[i].data();
        const double* restrict a_row = A[i].data();
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double *b_col = &B[0][j];          // address of B[0][j]
            for (int k = 0; k < nk; ++k) {
                sum += alpha * a_row[k] * b_col[k * nj]; // B[k][j]
            }
            tmp_row[j] = sum;
        }
    }

    /* Second matrix product with scaling:  D = beta*D + tmp * C  (ni x nl matrix) */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* restrict d_row = D[i].data();
        const double* restrict tmp_row = tmp[i].data();
        for (int j = 0; j < nl; ++j) {
            double sum = beta * d_row[j];
            for (int k = 0; k < nj; ++k) {
                sum += tmp_row[k] * C[k][j];
            }
            d_row[j] = sum;
        }
    }
}
