/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    // Parallelise the outermost loop: each thread works on a distinct row.
    // Since subsequent rows only depend on previous ones, no data races occur.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Access row i as a pointer for better locality.
        double* Ai = A[i].data();

        // Compute off‑diagonal elements: i > j
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            double* Aj = A[j].data();            // row j, for read only
            double* Ak = A[i].data();            // row i, reused
            // k-loop: dot product of A[i][0..j-1] and A[j][0..j-1]
            for (int k = 0; k < j; ++k) {
                sum += Ak[k] * Aj[k];
            }
            Ai[j] = (Ai[j] - sum) / Aj[j];       // Aj[j] == A[j][j]
        }

        // Diagonal element: i == j
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += Ai[k] * Ai[k];
        }
        Ai[i] = std::sqrt(Ai[i] - sum);
    }
}
