    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            // Local accumulation buffer – its lifetime is limited to this (r,q).
            // We reuse the buffer on each iteration to avoid repeated heap allocations.
            std::vector<double> local_sum(np, 0.0);

            // Compute the matrix‐vector products for all p.
            const std::vector<double>& Arq = A[r][q];
            for (int p = 0; p < np; ++p) {
                for (int s = 0; s < np; ++s) {
                    local_sum[p] += Arq[s] * C4[s][p];
                }
