/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B)
{
    // Number of interior rows/cols (excluding the boundary)
    const int inner = n - 2;

    // Reduce rank‑1 indexing into a single expression for speed
    const double coeff = 0.2;

    for (int t = 0; t < tsteps; ++t)
    {
        /* First half‑step: compute B from A */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= inner; ++i)
        {
            /* local pointers to the current row and neighboring rows to avoid
               repeated vector accesses */
            std::vector<double> const& rowA     = A[i];
            std::vector<double> const& rowA_up  = A[i-1];
            std::vector<double> const& rowA_down= A[i+1];
            std::vector<double>&       rowB     = B[i];
            std::vector<double>&       rowB_left= B[i-1];
            std::vector<double>&       rowB_right= B[i+1];

            for (int j = 1; j <= inner; ++j)
            {
                rowB[j] = coeff *
                          ( rowA[j] + rowA[j-1] + rowA[j+1] +
                            rowA_down[j] + rowA_up[j] );
            }
        }

        /* Second half‑step: compute A from B */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= inner; ++i)
        {
            std::vector<double> const& rowB     = B[i];
            std::vector<double> const& rowB_up  = B[i-1];
            std::vector<double> const& rowB_down= B[i+1];
            std::vector<double>&       rowA     = A[i];
            std::vector<double>&       rowA_left= A[i-1];
            std::vector<double>&       rowA_right= A[i+1];

            for (int j = 1; j <= inner; ++j)
