    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double ui1 = u1[i];
        double ui2 = u2[i];
        auto& Ai = A[i];
        for (int j = 0; j < n; ++j) {
            Ai[j] = Ai[j] + ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* 2) Update x[i] using the transpose of A
       (scales with beta).  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];
        for (int j = 0; j < n; ++j) {
            xi += beta * A[j][i] * y[j];
        }
        x[i] = xi;
    }

    /* 3) Add z to x  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* 4) Accumulate into w using A and the updated x   */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double wi = w[i];
        const auto& Ai = A[i];
        for (int j = 0; j < n; ++j) {
            wi += alpha * Ai[j] * x[j];
