void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* ------------------------------------
       1. Compute column means
       ------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / n;
    }

    /* ------------------------------------
       2. Center the data (subtract column means)
       ------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();                 // contiguous row
        const double* mu  = mean.data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mu[j];
        }
    }

    /* ------------------------------------
       3. Compute upper‑triangular covariance
          and mirror it to lower
       ------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* cov_i = cov[i].data();                // row i of covariance matrix
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double value = sum / (n - 1.0);
            cov_i[j] = value;          // upper‑triangular
            cov[j][i] = value;        // mirror to lower
        }
    }
}
```
This replacement keeps the exact observable behavior while improving performance:

* **Parallelisation**: All independent loops use OpenMP (`-fopenmp` flag) and static scheduling, giving good load balance on 8 threads.
* **Cache friendliness**: Row‑major access (`data[i][j]`) is preserved, but row pointers are cached in local variables for inner loops.
* **Reduced overhead**: Temporary copies (`row`, `mu`) avoid repeated `data[i][j]` lookups.
* **No change to function signature** or external API.

