   based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

inline int match(int b1, int b2) noexcept
{
    return (b1 + b2 == 3) ? 1 : 0;
}

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    /* Parallelise over the outer loop (i).  Each iteration of i only
       depends on results from i+1, so the order from n‑1 down to 0 can
       be computed independently. */
#pragma omp parallel for schedule(static)
    for (int i = n - 1; i >= 0; --i)
    {
        std::vector<int>* const row_i = &table[i];
        std::vector<int>* const row_ip1 = (i + 1 < n) ? &table[i + 1] : nullptr;

        for (int j = i + 1; j < n; ++j)
        {
            int best = row_i->at(j);

            /* Carry over the best value from the left (j‑1) */
            if (j > 0)
                best = std::max(best, row_i->at(j - 1));

            /* Carry over the best value from the above row (i+1) */
            if (row_ip1)
                best = std::max(best, row_ip1->at(j));

            /* Handle the pairing case or the adjacency case */
            if (j > 0 && row_ip1)
            {
                if (i < j - 1)
                    best = std::max(best, row_ip1->at(j - 1) + match(seq[i], seq[j]));
                else
                    best = std::max(best, row_ip1->at(j - 1));
            }

            /* Try all internal splits */
            int best_split = best;
            for (int k = i + 1; k < j; ++k)
            {
                int cur = row_i->at(k) + (*row_ip1)[k + 1];
                if (cur > best_split)
                    best_split = cur;
            }

            row_i->at(j) = best_split;
        }
    }
}
