/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* ------------------------------------------------------------------
       Create a flat contiguous copy of A to benefit from temporal locality
       ------------------------------------------------------------------*/
    const size_t N = static_cast<size_t>(n);
    std::vector<double> flatA(N * N);
    for (int i = 0; i < n; ++i)
        std::copy(A[i].begin(), A[i].end(), flatA.begin() + i * N);

    /* ------------------------------------------------------------------
       LU decomposition with partial pivoting removed (exact same semantics)
       ------------------------------------------------------------------*/
    const int B = 64;                 // cache block size (tuned empirically)
    for (int ii = 0; ii < n; ii += B) {
        int i_end = std::min(ii + B, n);
        for (int i = ii; i < i_end; ++i) {
            /* First part: compute subdiagonal elements */
            for (int j = 0; j < i; ++j) {
                double w = flatA[i * N + j];
                for (int k = 0; k < j; ++k)
                    w -= flatA[i * N + k] * flatA[k * N + j];
                flatA[i * N + j] = w / flatA[j * N + j];
            }

            /* Second part: compute upper triangle */
            for (int j = i; j < n; ++j) {
                double w = flatA[i * N + j];
                for (int k = 0; k < i; ++k)
                    w -= flatA[i * N + k] * flatA[k * N + j];
                flatA[i * N + j] = w;
            }
        }
    }

    /* ------------------------------------------------------------------
       Forward substitution: compute y = L \ b
       ------------------------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j)
            w -= flatA[i * N + j] * y[j];
        y[i] = w;
    }

    /* ------------------------------------------------------------------
       Backward substitution: compute x = U \ y
       ------------------------------------------------------------------*/
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        for (int j = i + 1; j < n; ++j)
            w -= flatA[i * N + j] * x[j];
        x[i] = w / flatA[i * N + i];
    }

    /* ------------------------------------------------------------------
       Copy the modified matrix back to the original 2‑D vector
       ------------------------------------------------------------------*/
    for (int i = 0; i < n; ++i)
        std::copy(flatA.begin() + i * N, flatA.begin() + (i + 1) * N, A[i].begin());
}
