void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double inv_n   = 1.0 / n;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ------------------------------------------------------------------
     *  1. Compute column means
     * ------------------------------------------------------------------ */
    #pragma omp parallel for reduction(+:mean[:m])
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            mean[j] += data[i][j];
    for (int j = 0; j < m; ++j)
        mean[j] *= inv_n;

    /* ------------------------------------------------------------------
     *  2. Compute column standard deviations
     * ------------------------------------------------------------------ */
    #pragma omp parallel for reduction(+:stddev[:m])
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double diff = data[i][j] - mean[j];
            stddev[j] += diff * diff;
        }
    }
    for (int j = 0; j < m; ++j) {
        stddev[j] = std::sqrt(stddev[j] * inv_n);
        if (stddev[j] <= eps) stddev[j] = 1.0;
    }

    /* ------------------------------------------------------------------
     *  3. Normalise data (zero‑mean, unit‑variance)
     * ------------------------------------------------------------------ */
    #pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] -= mean[j];
            data[i][j] *= inv_sqrt_n / stddev[j];
        }
    }

    /* ------------------------------------------------------------------
     *  4. Compute correlation matrix
     * ------------------------------------------------------------------ */
    /* Because we work with columns, the correlation matrix is just the
     * Gram matrix of the normalised data.  We compute it in a blocked,
     * cache‑friendly manner. */
    const int block = 64;   // good enough for most cache sizes

    for (int ii = 0; ii < m; ii += block) {
        int i_end = std::min(ii + block, m);
        for (int jj = ii; jj < m; jj += block) {
            int j_end = std::min(jj + block, m);

            for (int i = ii; i < i_end; ++i) {
                corr[i][i] = 1.0;  // diagonal
                for (int j = std::max(i+1, jj); j < j_end; ++j) {
                    double s = 0.0;
                    for (int k = 0; k < n; ++k)
                        s += data[k][i] * data[k][j];
                    corr[i][j] = corr[j][i] = s;
                }
            }
            /* Handle off-diagonal blocks where i is in [ii, i_end) and
             * j is in [jj, j_end) with i > j. */
            if (jj != ii) {
                for (int i = ii; i < i_end; ++i)
                    for (int j = jj; j < j_end; ++j) {
                        double s = 0.0;
                        for (int k = 0; k < n; ++k)
                            s += data[k][i] * data[k][j];
                        corr[i][j] = corr[j][i] = s;
                    }
            }
        }
    }
