/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* zero the result vector once (cheap and parallel) */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        y[j] = 0.0;
    }

    /* each thread keeps a private local y accumulation to avoid
       atomic updates.  After the outer loop the local sums are
       merged back into the global y. */
    #pragma omp parallel
    {
        /* per-thread local accumulation */
        std::vector<double> y_local(n, 0.0);

        /* main work: compute tmp[i] and contribute to y_local */
        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            double tmp_i = 0.0;
            /* first inner product: row i of A times x */
            for (int j = 0; j < n; ++j) {
                tmp_i += A[i][j] * x[j];
            }
            /* store the intermediate result */
            tmp[i] = tmp_i;

            /* second inner product: row i of A times tmp_i
               contributes to all elements of y */
            for (int j = 0; j < n; ++j) {
                y_local[j] += A[i][j] * tmp_i;
            }
        }

        /* merge local results into the global y */
        #pragma omp critical
        {
            for (int j = 0; j < n; ++j) {
                y[j] += y_local[j];
            }
        }
    }
}
