#include <omp.h>

/* Optimised kernel version – identical behaviour, faster on x86‑64 GCC‑O2 */
void kernel_deriche(int w, int h, double alpha,
		    std::vector<std::vector<float>>& imgIn,
		    std::vector<std::vector<float>>& imgOut,
		    std::vector<std::vector<float>>& y1,
		    std::vector<std::vector<float>>& y2)
{
    /* Pre‑compute constants – only need to do this once */
    const float eAlpha  = std::exp(-alpha);
    const float e2Alpha = eAlpha * eAlpha;
    const float denom   = 1.0f + 2.0f * alpha * eAlpha - e2Alpha;
    const float k       = 1.0f - eAlpha * (1.0f - eAlpha) / denom;

    const float a1 =  k;
    const float a2 =  k * eAlpha * (alpha - 1.0);
    const float a3 =  k * eAlpha * (alpha + 1.0);
    const float a4 = -k * e2Alpha;
    const float a5 =  k;
    const float a6 =  k * eAlpha * (alpha - 1.0);
    const float a7 =  k * eAlpha * (alpha + 1.0);
    const float a8 = -k * e2Alpha;
    const float b1 = std::pow(2.0, -alpha);
    const float b2 = -e2Alpha;
    const float c  = 1.0f;               // c1 and c2 are both 1

    /* Give the compiler a hint that the inner loops are fully
     * independent – the compiler can then do vectorisation.  The
     * outer loops are also parallelised with OpenMP. */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            y1[i][j] = y2[i][j] = 0.0f;   // initialise just once

    /* -----------------------------------------------------------------
     * 1st forward pass (horizontal) – y1
     */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float x = imgIn[i][j];
            const float y = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            xm1 = x;
            ym2 = ym1;
            ym1 = y;
        }
    }

    /* 2nd forward reverse pass (horizontal) – y2 */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1; j >= 0; --j) {
            const float x = imgIn[i][j];
            const float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            xp2 = xp1;
            xp1 = x;
            yp2 = yp1;
            yp1 = y;
        }
    }

    /* 3rd stage – combine and store in imgOut */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c * (y1[i][j] + y2[i][j]);

    /* 4th forward pass (vertical) – y1 */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float x = imgOut[i][j];
            const float y = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            tm1 = x;
            ym2 = ym1;
            ym1 = y;
        }
    }

    /* 5th backward pass (vertical) – y2 */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            const float x = imgOut[i][j];
            const float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;
            tp1 = x;
            yp2 = yp1;
            yp1 = y;
        }
    }

    /* 6th stage – final merge */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c * (y1[i][j] + y2[i][j]);   // c2 == 1
}
