/*
 * Optimised version of kernel_adi.
 *
 * The original implementation used std::vector<std::vector<double>>,
 * which incurs per‑element bounds checks and many small allocations.
 * This replacement flattens the 2‑D arrays into 1‑D blocks of contiguous
 * memory, removes bounds checks, uses pointer arithmetic and
 * exploits loop‑to‑loop dependencies by caching the repeated coefficients.
 * OpenMP is used to parallelise the outermost loop over the “i” dimension,
 * which is independent across iterations.
 *
 * The function signature remains unchanged; the caller must still
 * supply three‑dimensional `std::vector<std::vector<double>>`
 * objects that have exactly `n` rows and `n` columns each.
 * Internally the code re‑creates the flattened buffers and copies the data
 * back to the input objects before returning.
 */

static inline void kernel_adi_opt(int tsteps, int n,
                                  std::vector<std::vector<double>>& u,
                                  std::vector<std::vector<double>>& v,
                                  std::vector<std::vector<double>>& p,
                                  std::vector<std::vector<double>>& q) {
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0, B2 = 1.0;

    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a  = -mul1 / 2.0;
    const double b  = 1.0 + mul1;
    const double c  = a;
    const double d  = -mul2 / 2.0;
    const double e  = 1.0 + mul2;
    const double f  = d;

    /* allocate flat buffers: stride = n */
    const std::size_t stride = n;
    std::vector<double> U_flat(n * n);
    std::vector<double> V_flat(n * n);
    std::vector<double> P_flat(n * n);
    std::vector<double> Q_flat(n * n);

    /* copy input data into flat buffers */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            U_flat[i * stride + j] = u[i][j];

    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            V_flat[i * stride + j] = v[i][j];

    /* -------------------------------------------------------------- */
    const double A = a, B = b, C = c, D = d, E = e, F = f;

    const double mul_a_b = 1.0 / B;     // common factor 1/(a*p+b)
    const double mul_d_e = 1.0 / E;     // common factor 1/(d*p+e)

#pragma omp parallel
    {
        for (int t = 1; t <= tsteps; ++t) {

            /* phase 1 – sweep over columns (i) */
#pragma omp for schedule(static)
            for (int i = 1; i < n - 1; ++i) {
                double *p_row = &P_flat[i * stride];
                double *q_row = &Q_flat[i * stride];
                double *v_col = &V_flat[0 * stride + i];

                /* initialise boundary values */
                v_col[0] = 1.0;
                p_row[0] = 0.0;
                q_row[0] = v_col[0];

                /* forward sweep (j = 1 .. n-2) */
                for (int j = 1; j < n - 1; ++j) {
                    double denom = A * p_row[j - 1] + B;
                    p_row[j] = -C / denom;
                    double numerator = (-D * U_flat[j * stride + (i - 1)]
                                        + (1.0 + 2.0 * D) * U_flat[j * stride + i]
                                        - F * U_flat[j * stride + (i + 1)]
                                        - A * q_row[j - 1]);
                    q_row[j] = numerator / denom;
                }

                /* boundary at the other side */
                v_col[n - 1] = 1.0;

                /* backward sweep (j = n-2 .. 1) */
                for (int j = n - 2; j >= 1; --j)
                    v_col[j] = p_row[j] * v_col[j + 1] + q_row[j];
            }

            /* phase 2 – sweep over rows (i) */
#pragma omp for schedule(static)
            for (int i = 1; i < n - 1; ++i) {
                double *p_row = &P_flat[i * stride];
                double *q_row = &Q_flat[i * stride];
                double *u_col = &U_flat[0 * stride + i];

                /* initialise boundary values */
                u_col[0] = 1.0;
                p_row[0] = 0.0;
                q_row[0] = u_col[0];

                /* forward sweep (j = 1 .. n-2) */
                for (int j = 1; j < n - 1; ++j) {
                    double denom = D * p_row[j - 1] + E;
                    p_row[j] = -F / denom;
                    double numerator = (-A * V_flat[(i - 1) * stride + j]
                                        + (1.0 + 2.0 * A) * V_flat[i * stride + j]
                                        - C * V_flat[(i + 1) * stride + j]
                                        - D * q_row[j - 1]);
                    q_row[j] = numerator / denom;
                }

                /* boundary at the other side */
                u_col[n - 1] = 1.0;

                /* backward sweep (j = n-2 .. 1) */
                for (int j = n - 2; j >= 1; --j)
                    u_col[j] = p_row[j] * u_col[j + 1] + q_row[j];
            }
        }
    }

    /* copy results back to the original 2‑D containers */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            u[i][j] = U_flat[i * stride + j];

    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            v[i][j] = V_flat[i * stride + j];
}
